from flask import Flask, request, jsonify
from functools import wraps
import sqlite3
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', 'default-secret-key')

# Database setup
def init_db():
    conn = sqlite3.connect('tokens.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS access_tokens
                 (token TEXT PRIMARY KEY, user_id TEXT, expires_at TIMESTAMP)''')
    conn.commit()
    conn.close()

# Token validation function
def validate_token(token):
    conn = sqlite3.connect('tokens.db')
    c = conn.cursor()
    c.execute("SELECT user_id FROM access_tokens WHERE token = ? AND expires_at > datetime('now')", (token,))
    result = c.fetchone()
    conn.close()
    return result is not None

# Decorator for requiring OAuth tokens
def require_oauth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401
        
        token = auth_header.split(' ')[1]
        if not validate_token(token):
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        return f(*args, **kwargs)
    return decorated_function

# Example protected endpoints
@app.route('/api/protected', methods=['GET'])
@require_oauth
def protected_endpoint():
    return jsonify({'message': 'This is a protected endpoint'})

@app.route('/api/user', methods=['GET'])
@require_oauth
def user_endpoint():
    return jsonify({'user': 'authenticated_user'})

@app.route('/api/data', methods=['GET'])
@require_oauth
def data_endpoint():
    return jsonify({'data': 'sensitive_data'})

if __name__ == '__main__':
    init_db()
